{"code":"import json
from pathlib import Path
p = Path(var_call_C9qcVttwHc7nHk3C6JaXP5aS)
records = json.loads(p.read_text())

# Build list of businesses accepting credit cards with inferred categories from description
out = []
for r in records:
    attrs = r.get('attributes') or {}
    accepts = attrs.get('BusinessAcceptsCreditCards')
    if accepts in (True, 'True', 'true', 'TRUE', "u'True'"):
        biz_id = r.get('business_id')
        if biz_id and biz_id.startswith('businessid_'):
            biz_ref = 'businessref_' + biz_id.split('_',1)[1]
        else:
            biz_ref = biz_id
        desc = r.get('description') or ''
        # attempt to parse categories from description by splitting after 'in' and commas
        categories = None
        # Look for 'offers a range of services in X' or 'in the category of X' patterns
        if 'offers a range of services in' in desc:
            try:
                categories = desc.split('offers a range of services in',1)[1]
                categories = categories.split('.')[0]
            except:
                categories = None
        elif "in the category of" in desc:
            try:
                categories = desc.split('in the category of',1)[1].split('.')[0]
            except:
                categories = None
        elif 'offers a diverse range of services' in desc:
            try:
                categories = desc.split('offers a diverse range of services',1)[1].split('in the fields of')[-1].split('.')[0]
            except:
                categories = None
        if categories:
            # split by commas
            cats_list = [c.strip().strip("'\"") for c in categories.split(',') if c.strip()]
        else:
            cats_list = None
        out.append({'business_ref': biz_ref, 'business_id': biz_id, 'name': r.get('name'), 'parsed_categories': cats_list})

print('__RESULT__:')
print(json.dumps(out))"}

