{"code":"import json
from pathlib import Path
from collections import Counter

p = Path(var_call_C9qcVttwHc7nHk3C6JaXP5aS)
records = json.loads(p.read_text())

def extract_cats(desc):
    if not desc:
        return []
    desc = desc.replace('\n',' ').replace('\r',' ')
    markers = ['offers a range of services in', 'offers a diverse range of services in', 'in the category of', 'in the category', 'offers a range of services', 'offers a diverse range of services']
    seg = None
    for marker in markers:
        if marker in desc:
            i = desc.find(marker)
            seg = desc[i+len(marker):]
            break
    if seg is None:
        if ' in ' in desc:
            i = desc.rfind(' in ')
            seg = desc[i+4:]
        else:
            return []
    seg = seg.split('.')[0]
    parts = []
    for part in seg.split(','):
        for sub in part.split(' and '):
            sub = sub.strip().strip("'\"")
            if sub:
                parts.append(sub)
    return parts

cat_counter = Counter()
cat_to_refs = {}
for r in records:
    attrs = r.get('attributes') or {}
    accepts = attrs.get('BusinessAcceptsCreditCards')
    if accepts in (True, 'True', 'true', 'TRUE', "u'True'"):
        biz_id = r.get('business_id')
        if biz_id and biz_id.startswith('businessid_'):
            biz_ref = 'businessref_' + biz_id.split('_',1)[1]
        else:
            biz_ref = biz_id
        desc = r.get('description') or ''
        cats = extract_cats(desc)
        if cats:
            for c in cats:
                cat = c.strip()
                cat_counter[cat] += 1
                cat_to_refs.setdefault(cat, set()).add(biz_ref)

if cat_counter:
    top_cat, top_count = cat_counter.most_common(1)[0]
    top_refs = sorted(list(cat_to_refs[top_cat]))
else:
    top_cat = None
    top_count = 0
    top_refs = []

result = {'top_category': top_cat, 'count': top_count, 'business_refs': top_refs}
print('__RESULT__:')
print(json.dumps(result))"}

