        'offers a diverse range of services in',
        'in the category of',
        'in the category',
        'offers a range of services',
        'offers a diverse range of services'
    ]
    seg = None
    for marker in markers:
        idx = desc.find(marker)
        if idx != -1:
            seg = desc[idx + len(marker):]
            break
    if seg is None:
        idx = desc.rfind(' in ')
        if idx != -1:
            seg = desc[idx+4:]
        else:
            return []
    seg = seg.split('.')[0]
    parts = []
    for part in seg.split(','):
        for sub in part.split(' and '):
            sub = sub.strip().strip("'\"")
            if sub:
                parts.append(sub)
    return parts

