cat_to_refs = {}
ref_to_name = {}

for r in records:
    attrs = r.get('attributes') or {}
    accepts = attrs.get('BusinessAcceptsCreditCards')
    accepts_flag = False
    if accepts is True:
        accepts_flag = True
    else:
        try:
            if str(accepts).lower() in truthy:
                accepts_flag = True
        except:
            accepts_flag = False
    if not accepts_flag:
        continue
    biz_id = r.get('business_id')
    if biz_id and biz_id.startswith('businessid_'):
        biz_ref = 'businessref_' + biz_id.split('_',1)[1]
    else:
        biz_ref = biz_id
